INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES
('Play Ransomware Targets Managed Service Providers for Downstream Access', 'play-ransomware-msp-downstream-access', 'Play ransomware compromises three MSPs to deploy ransomware across 120+ downstream client organizations simultaneously.', 'Play ransomware group compromised three managed service providers using FortiOS vulnerabilities, then used the MSPs remote management tools to deploy ransomware to over 120 client organizations. Downstream victims span healthcare, legal, accounting, and manufacturing sectors. CISA has issued specific guidance for MSPs on securing RMM tools.', 'high', 'ransomware', '{}', '{"FortiOS","ConnectWise ScreenConnect","Datto RMM","MSP Infrastructure"}', '{"Play Ransomware"}', '{"technology","healthcare","finance","manufacturing"}', 'MSP Compromise / RMM Tool Abuse', 'CISA / MS-ISAC Advisory', 'https://www.cisa.gov', '2026-03-09T15:00:00Z', '2026-03-10T11:00:00Z', '2026-03-05T00:00:00Z', '2026-03-05T00:00:00Z', NULL, true, '{"CISA","MS-ISAC"}', '{"ransomware","msp","supply-chain","rmm-abuse","play"}', 'Global'),

('Critical WordPress Plugin Vulnerability Affects 5 Million Sites', 'wordpress-plugin-critical-5m-sites', 'Unauthenticated SQL injection in a top WordPress security plugin allows database takeover. 5 million active installations at risk.', 'CVE-2026-8001 is an unauthenticated SQL injection vulnerability in a widely-used WordPress security plugin with over 5 million active installations. Attackers can extract admin credentials, modify database content, or create backdoor admin accounts. WPScan detected active exploitation within 24 hours of disclosure. Plugin vendor released a patch but adoption is slow.', 'high', 'vulnerability', '{"CVE-2026-8001"}', '{"WordPress","WordPress Security Plugin","MySQL/MariaDB","PHP"}', '{}', '{"technology","retail","education"}', 'Web Application / SQL Injection', 'WPScan / Wordfence', 'https://wpscan.com', '2026-03-08T12:00:00Z', '2026-03-09T08:00:00Z', '2026-03-06T00:00:00Z', '2026-03-07T00:00:00Z', '2026-03-07T00:00:00Z', true, '{"WPScan","Wordfence","CISA"}', '{"wordpress","sql-injection","web-application","mass-exploitation"}', 'Global'),

('ALPHV Successor RansomHub Becomes Top Ransomware Threat in Q1 2026', 'ransomhub-top-ransomware-q1-2026', 'RansomHub, believed to include former ALPHV/BlackCat operators, claims 185+ victims in Q1 2026 alone. Now the most prolific ransomware operation.', 'RansomHub has rapidly grown to become the most active ransomware group globally, claiming 185+ victims in Q1 2026. The group offers 90% revenue share to affiliates, the most competitive in the RaaS market. Uses a Golang-based encryptor targeting Windows, Linux, and ESXi. Notable victims include manufacturing, healthcare, and government organizations across 30+ countries.', 'high', 'ransomware', '{}', '{"Windows Server","Linux Enterprise","VMware ESXi","NAS Systems"}', '{"ALPHV/BlackCat"}', '{"manufacturing","healthcare","government","finance","technology"}', 'VPN Exploitation / Phishing / Credential Abuse', 'Group-IB / Recorded Future', 'https://www.group-ib.com', '2026-03-07T10:00:00Z', '2026-03-08T09:00:00Z', '2026-01-01T00:00:00Z', NULL, NULL, true, '{"Group-IB","Recorded Future"}', '{"ransomware","raas","ransomhub","blackcat","statistics"}', 'Global'),

('Microsoft Patches 97 Vulnerabilities Including Three Actively Exploited Zero-Days', 'microsoft-march-2026-patch-tuesday', 'March 2026 Patch Tuesday addresses 97 CVEs with three actively exploited zero-days in Windows kernel, NTLM, and Hyper-V.', 'Microsoft March 2026 Patch Tuesday addresses 97 vulnerabilities across Windows, Office, Azure, and Exchange. Three zero-days are under active exploitation: CVE-2026-21399 (Windows kernel EoP), CVE-2026-21400 (NTLM hash leak), CVE-2026-21401 (Hyper-V guest escape). CISA added all three to KEV catalog with 21-day remediation deadline.', 'critical', 'vulnerability', '{"CVE-2026-21399","CVE-2026-21400","CVE-2026-21401"}', '{"Windows 10/11","Windows Server 2022/2025","Hyper-V","NTLM","Microsoft Exchange"}', '{}', '{"technology","government","finance","healthcare","education"}', 'Multiple Vectors', 'Microsoft MSRC', 'https://msrc.microsoft.com', '2026-03-12T17:00:00Z', '2026-03-13T10:00:00Z', '2026-03-01T00:00:00Z', '2026-03-01T00:00:00Z', '2026-03-12T00:00:00Z', true, '{"Microsoft","CISA"}', '{"patch-tuesday","zero-day","windows","hyper-v","ntlm"}', 'Global'),

('FBI Warns of AI-Generated Deepfake Voice Attacks Targeting Corporate Executives', 'fbi-deepfake-voice-attacks-executives', 'FBI issues alert on rising deepfake voice attacks using AI-cloned executive voices to authorize fraudulent wire transfers. $68M stolen in Q1 2026.', 'FBI warns of a surge in AI-generated deepfake voice attacks targeting corporate finance teams. Threat actors clone C-suite executive voices from earnings calls, conference presentations, and social media. The cloned voices are used in real-time phone calls to authorize urgent wire transfers. At least $68M has been stolen across 15 confirmed incidents in Q1 2026. FBI recommends implementing verbal code words for financial authorization.', 'high', 'phishing', '{}', '{"AI Voice Cloning Tools","VoIP Systems","Corporate Finance Systems"}', '{}', '{"finance","technology","manufacturing","retail"}', 'AI-Generated Voice Deepfakes / Vishing', 'FBI IC3', 'https://www.ic3.gov', '2026-03-06T09:00:00Z', '2026-03-07T14:00:00Z', '2026-01-15T00:00:00Z', NULL, NULL, true, '{"FBI","CISA"}', '{"deepfake","ai","vishing","wire-fraud","social-engineering"}', 'United States'),

('Critical SonicWall SMA Gateway Auth Bypass Under Active Exploitation', 'sonicwall-sma-auth-bypass-active-exploitation', 'Authentication bypass in SonicWall SMA 1000 series gateways allows unauthenticated admin access. Active exploitation confirmed by CISA.', 'CVE-2026-5135 is a critical authentication bypass in SonicWall SMA 1000 series. Unauthenticated attackers can gain admin access to the management interface and pivot into internal networks. CISA added to KEV catalog after confirming active exploitation. Arctic Wolf observed ransomware deployment following SMA compromise.', 'critical', 'vulnerability', '{"CVE-2026-5135"}', '{"SonicWall SMA 1000","SonicWall SMA 100","SonicOS"}', '{}', '{"finance","healthcare","government","retail"}', 'Network / Management Interface', 'SonicWall PSIRT / Arctic Wolf', 'https://psirt.global.sonicwall.com', '2026-03-05T11:00:00Z', '2026-03-06T09:00:00Z', '2026-02-25T00:00:00Z', '2026-03-01T00:00:00Z', '2026-03-05T00:00:00Z', true, '{"CISA","SonicWall","Arctic Wolf"}', '{"sonicwall","auth-bypass","vpn","network-edge","ransomware-precursor"}', 'Global'),

('European Banking Authority Reports 340% Increase in DDoS Attacks on Banks', 'eba-ddos-attacks-banks-340-percent', 'EBA reports unprecedented surge in DDoS attacks against European financial institutions. Pro-Russian hacktivist groups responsible for majority of attacks.', 'The European Banking Authority reports a 340% increase in DDoS attacks against EU financial institutions in Q1 2026 compared to Q1 2025. Pro-Russian hacktivist groups including NoName057(16) and KillNet successors are responsible for the majority. While most attacks cause temporary service disruption, several have been used as smokescreens for simultaneous data exfiltration attempts. EBA has issued updated guidance on DDoS resilience for systemically important institutions.', 'medium', 'ddos', '{}', '{"Banking Platforms","Payment Processing Systems","SWIFT Infrastructure"}', '{}', '{"finance","government"}', 'DDoS / Volumetric and Application Layer', 'European Banking Authority', 'https://www.eba.europa.eu', '2026-03-04T08:00:00Z', '2026-03-05T12:00:00Z', '2026-01-01T00:00:00Z', NULL, NULL, true, '{"EBA","ENISA"}', '{"ddos","finance","hacktivism","russia","europe"}', 'Europe'),

('Scattered Spider Member Arrested in Spain — FBI Unseals Indictment', 'scattered-spider-member-arrested-spain', 'FBI and Spanish police arrest alleged Scattered Spider member linked to MGM, Caesars, and healthcare breaches. Indictment details $100M+ in damages.', 'A 22-year-old UK national allegedly affiliated with Scattered Spider was arrested in Mallorca, Spain, following an FBI-led investigation. The unsealed indictment links the suspect to intrusions at MGM Resorts, Caesars Entertainment, and multiple healthcare organizations. Total damages estimated at over $100 million. The arrest is part of a broader international effort to dismantle the group.', 'low', 'apt', '{}', '{"N/A"}', '{"Scattered Spider"}', '{"finance","healthcare","technology","retail"}', 'N/A — Law Enforcement Action', 'FBI / Europol', 'https://www.fbi.gov', '2026-03-03T16:00:00Z', '2026-03-04T10:00:00Z', NULL, NULL, NULL, true, '{"FBI","Europol","Spanish National Police"}', '{"law-enforcement","scattered-spider","arrest","indictment"}', 'Spain / United States'),

('GitHub Actions Supply Chain Attack Injects Malware Into CI/CD Pipelines', 'github-actions-supply-chain-cicd', 'Compromised GitHub Action used by 23,000+ repositories injects credential-stealing code into CI/CD pipelines. Broad exposure across enterprise repositories.', 'A popular GitHub Action with 23,000+ repository users was compromised after the maintainer account was hijacked. The malicious version exfiltrates CI/CD secrets including cloud credentials, NPM tokens, and Docker registry passwords during pipeline execution. GitHub has revoked the compromised versions and is notifying affected organizations. The incident highlights ongoing risks in CI/CD supply chain security.', 'high', 'supply-chain', '{}', '{"GitHub Actions","CI/CD Pipelines","Docker Registry","NPM Registry"}', '{}', '{"technology","finance","healthcare"}', 'Supply Chain / CI/CD Pipeline Compromise', 'GitHub Security Advisory', 'https://github.com/advisories', '2026-03-02T19:00:00Z', '2026-03-03T12:00:00Z', '2026-03-02T14:00:00Z', NULL, NULL, true, '{"GitHub","CISA"}', '{"supply-chain","cicd","github-actions","credential-theft","devops"}', 'Global'),

('CISA Adds 12 Vulnerabilities to Known Exploited Vulnerabilities Catalog in One Week', 'cisa-12-kevs-one-week-record', 'CISA adds 12 vulnerabilities to KEV catalog in a single week — the highest since the catalog launch. Reflects accelerating exploitation pace.', 'CISA added 12 vulnerabilities to the Known Exploited Vulnerabilities catalog in a single week, the highest since the catalog launch in November 2021. The additions include flaws in Palo Alto PAN-OS, Fortinet FortiManager, Ivanti Connect Secure, SonicWall SMA, and multiple Microsoft products. Federal agencies have 21 days for most to remediate. The pace reflects what CISA Director calls "an unprecedented acceleration in adversary exploitation timelines."', 'medium', 'vulnerability', '{}', '{"Multiple Vendors","Network Edge Devices","Microsoft Products","VPN Appliances"}', '{}', '{"government","technology","finance","healthcare","defense"}', 'Multiple / Various', 'CISA', 'https://www.cisa.gov/known-exploited-vulnerabilities-catalog', '2026-03-01T10:00:00Z', '2026-03-02T08:00:00Z', NULL, NULL, NULL, true, '{"CISA"}', '{"kev","vulnerability-management","patching","compliance","cisa"}', 'United States'),

('Google Project Zero Discloses Linux Kernel Zero-Day in eBPF Subsystem', 'linux-kernel-ebpf-zero-day', 'Google Project Zero discloses a critical privilege escalation in the Linux kernel eBPF verifier. Affects cloud workloads, containers, and Android.', 'CVE-2026-0399 is a verifier bypass in the Linux kernel eBPF subsystem allowing unprivileged users to escalate to root. Impacts kernel versions 5.15 through 6.8. Particularly dangerous in multi-tenant cloud environments and container orchestration platforms where eBPF is widely used. Kernel patches released for all LTS branches. Cloud providers patching managed instances.', 'high', 'vulnerability', '{"CVE-2026-0399"}', '{"Linux Kernel 5.15-6.8","Ubuntu","RHEL","Container Runtimes","Android"}', '{}', '{"technology","finance","government","telecommunications"}', 'Local Privilege Escalation / eBPF Verifier Bypass', 'Google Project Zero', 'https://googleprojectzero.blogspot.com', '2026-02-28T15:00:00Z', '2026-03-01T10:00:00Z', '2026-02-15T00:00:00Z', NULL, '2026-02-28T00:00:00Z', true, '{"Google Project Zero","Linux Kernel Team"}', '{"linux","kernel","ebpf","privilege-escalation","cloud","containers"}', 'Global'),

('Iranian APT Targets US Defense Industrial Base with New MalwareLoader', 'iranian-apt-defense-industrial-base', 'Iranian threat actor Peach Sandstorm deploys novel loader in campaign against US defense industrial base. Targets include drone and satellite manufacturers.', 'Microsoft Threat Intelligence has identified Iranian threat actor Peach Sandstorm (APT33/Elfin) deploying a new custom loader dubbed FalconDrop against US defense industrial base companies. Targets include manufacturers of drones, satellites, and radar systems. Initial access via password spray attacks against Azure AD. The loader evades detection by masquerading as legitimate Windows Update components.', 'high', 'apt', '{}', '{"Azure AD","Windows Server","Defense Industrial Systems"}', '{}', '{"defense","manufacturing","government","technology"}', 'Password Spray / Custom Malware Loader', 'Microsoft Threat Intelligence', 'https://www.microsoft.com/security/blog', '2026-02-27T11:00:00Z', '2026-02-28T09:00:00Z', '2026-02-10T00:00:00Z', '2026-02-10T00:00:00Z', NULL, true, '{"Microsoft","CISA","NSA"}', '{"iran","defense","password-spray","apt33","custom-malware"}', 'United States'),

('Major US Airport Systems Hit by Coordinated Ransomware Attack', 'us-airport-systems-coordinated-ransomware', 'Coordinated ransomware attack disrupts systems at four major US airports. Flight information, baggage handling, and check-in systems affected.', 'A coordinated ransomware attack disrupted operations at four major US airports, affecting flight information displays, automated baggage handling, and self-service check-in kiosks. The attack is attributed to a ransomware affiliate exploiting a common vendor used by all four airports. TSA and CISA activated emergency response protocols. Manual backup procedures kept flights operational but caused significant delays. No impact to air traffic control or flight safety systems.', 'high', 'ransomware', '{}', '{"Airport Management Systems","Baggage Handling Systems","FIDS","Check-in Kiosks"}', '{}', '{"government","technology","manufacturing"}', 'Third-Party Vendor Compromise / Ransomware', 'TSA / CISA', 'https://www.tsa.gov', '2026-02-26T06:00:00Z', '2026-02-27T14:00:00Z', '2026-02-26T03:00:00Z', '2026-02-26T03:00:00Z', NULL, true, '{"TSA","CISA","FBI"}', '{"ransomware","airport","transportation","critical-infrastructure"}', 'United States'),

('Apple Patches Actively Exploited WebKit Zero-Day in iOS and macOS', 'apple-webkit-zero-day-ios-macos', 'Apple releases emergency updates for iOS 18.4 and macOS 15.4 to fix WebKit zero-day used in targeted attacks. Sophisticated exploit chain confirmed.', 'Apple has released emergency security updates for CVE-2026-23529, a use-after-free vulnerability in WebKit being actively exploited in "extremely sophisticated" targeted attacks. The vulnerability affects iOS, iPadOS, macOS, visionOS, and Safari. Apple credits Citizen Lab for the discovery, suggesting surveillance-related exploitation. Update to iOS 18.4, macOS 15.4, and Safari 18.4 immediately.', 'high', 'zero-day', '{"CVE-2026-23529"}', '{"iOS 18","iPadOS 18","macOS Sequoia 15","Safari","visionOS"}', '{}', '{"technology","government"}', 'Web / Malicious Web Content', 'Apple / Citizen Lab', 'https://support.apple.com/en-us/HT201222', '2026-02-25T18:00:00Z', '2026-02-26T10:00:00Z', '2026-02-20T00:00:00Z', '2026-02-20T00:00:00Z', '2026-02-25T00:00:00Z', true, '{"Apple","Citizen Lab"}', '{"apple","webkit","zero-day","ios","surveillance","mobile"}', 'Global');
